/* Codex Brand Tokens — OptiStock Visual Suite (inlined) */
.bullet-chart-container {
  width: 100%;
  height: 100%;
  overflow: hidden;
  font-family: "Segoe UI", Tahoma, Geneva, Verdana, sans-serif;
  box-sizing: border-box;
  padding: 4px;
}
.bullet-chart-svg-area {
  width: 100%;
  height: 100%;
  overflow: hidden;
}
.bullet-svg {
  display: block;
}
.bullet-svg .bullet-label {
  font-family: "Segoe UI", Tahoma, Geneva, Verdana, sans-serif;
  user-select: none;
  cursor: default;
}
.bullet-svg .bullet-value-label {
  font-family: "Segoe UI", Tahoma, Geneva, Verdana, sans-serif;
  user-select: none;
  cursor: default;
}
.bullet-svg .bullet-row rect,
.bullet-svg .bullet-row-vert rect {
  transition: opacity 0.15s ease;
}
.bullet-svg .bullet-row:hover rect,
.bullet-svg .bullet-row-vert:hover rect {
  opacity: 0.88;
}
.bullet-empty {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  height: 100%;
  color: #5e5d5a;
  text-align: center;
  font-family: "Segoe UI", Tahoma, Geneva, Verdana, sans-serif;
  padding: 16px;
}
.bullet-empty .bullet-empty-icon {
  font-size: 32px;
  color: #e8e2d3;
  margin-bottom: 8px;
}
.bullet-empty .bullet-empty-text {
  font-size: 13px;
  line-height: 1.4;
  max-width: 200px;
}
.bullet-empty .bullet-empty-text strong {
  color: #130064;
}
